const allFirstData = $("Get Body").first().json.body

function flushCpf(cpf) {
  if (cpf) {
    let cpf_flushed = String(cpf || "");
    return cpf_flushed.padStart(11, "0");
  }
}


if (allFirstData.cpf) {
  let cleared_cpf = flushCpf(allFirstData.cpf);
  return {
    "cpf": cleared_cpf,

    "searched": JSON.stringify({"cpf": cleared_cpf}),
    "endpoint": "cpf",
    "key": "cpf"
  }
}

return {
  "beneficio": allFirstData.beneficio,
  "searched": JSON.stringify({"matricula": allFirstData.beneficio}),
  "endpoint": "offline",
  "key": "beneficio"
}

