UPDATE external
SET payload = CONVERT('{{ JSON.stringify($('UTF-8 Convert').item.json.decoded) }}' USING utf8mb4), updated_at = NOW() 
WHERE source_info = 'nova_era' AND searched_hash = '{{ $('Crypto Md5 Converter').item.json.searched_hash }}';

INSERT INTO external (source_info, searched_hash, searched, payload, updated_at)
SELECT 'nova_era', '{{ $('Crypto Md5 Converter').item.json.searched_hash }}', '{{ $('Data For Search').item.json.searched }}', '{{ JSON.stringify($('UTF-8 Convert').item.json.decoded) }}', NOW()
WHERE NOT EXISTS (
    SELECT 1 FROM external WHERE source_info = 'nova_era' AND searched_hash = '{{ $('Crypto Md5 Converter').item.json.searched_hash }}'
);

