      const parsed = JSON.parse(rawString);
      finalObject = Array.isArray(parsed) ? parsed[0] : parsed;
    } catch (e) {
      finalObject = { error: "Erro ao processar string", original: rawString };
    }
  } 
  else if (input.Beneficiario) {
    // Se já for o objeto aberto, apenas usa ele
    const { decoded, payload_string_db, ...cleanData } = input;
    finalObject = cleanData;
  } 
  else {
    finalObject = input;
  }

  return {
    json: {
      ...input,
      // Força a saída a ser SEMPRE um Array para o SQL não quebrar
      decoded: [finalObject] 
    }
  };
});

return items.map(item => {
  const data = item.json.data;

  // Garante que é string
  const input = String(data);

  // Corrige unicode duplamente escapado: \\u00e9 → \u00e9
  const unescaped = input.replace(/\\\\u/g, '\\u');

  // Decodifica sequências \uXXXX em caracteres reais
  const decoded = JSON.parse(`"${unescaped.replace(/"/g, '\\"')}"`);

  return {
    json: {
      decoded: decoded
    }
  };
});

return items.map(item => {
  const data = item.json.data;

  // Primeiro parse: tira o nível extra de escape
  const once = JSON.parse(data);

  // Se ainda vier como string (com escapes), faz outro parse
  const final = (typeof once === "string") ? JSON.parse(once) : once;

  return {
    json: {
      decoded: final
    }
  };
});

